head.script:
scwin.retrieveType = 0;
scwin.oldData = "";
scwin.eventCnt = 0;

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {

    const codeOptions = [
        { grpCd: "SD060", compID: "acb_expClsCd" }, // 셀렉트
        { grpCd: "OP241", compID: "gr_agreementVolumeResults:wrkMthdCd" }, // 셀렉트
    ];
    $c.data.setCommonCode(codeOptions);


    const param= [
        {
            method: "getGridCombo",
            param1: "StevedoringWagesResultsEBC",
            param2: "retriveWrkStpList",
            compID: "gr_agreementVolumeResults:sellItemCd"
        }
    ];
    $c.data.setGauceUtil(param);


    ed_cvsslMgntNo.focus();

    $c.gus.cfDisableBtnOnly([udc_gr_Row, btn_save]);


};


//-------------------------------------------------------------------------
// 대문자 변환
//-------------------------------------------------------------------------
scwin.onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};


//-------------------------------------------------------------------------
// 조회 (입력물량)
//-------------------------------------------------------------------------
scwin.btn_retrieve = async function (e) {
    scwin.retrieveType = "1"; // 상단 조회에서 오면 *type(1) :입력물량  , type(2): 협정물량 불러오기 */   

    if(!await $c.gus.cfValidate([ed_cvsslMgntNo,acb_expClsCd])) {
        return;
    }

    dma_condition.set("cvsslMgntNo", ed_cvsslMgntNo.getValue());
    dma_condition.set("expimpClsCd", acb_expClsCd.getValue()); 
    dma_condition.set("isModifyOnly" , "true");

    $c.sbm.execute(sbm_retrieve);


};


//-------------------------------------------------------------------------
// 조회 (협정물량)
//-------------------------------------------------------------------------
scwin.btn_agreedVolumeRetrieve_onClick = async function (e) {
    scwin.retrieveType = "2";

    if (!await $c.gus.cfValidate([ed_cvsslMgntNo,acb_expClsCd])){
    	return;
    }    

    dma_condition.set("cvsslMgntNo", ed_cvsslMgntNo.getValue());
    dma_condition.set("expimpClsCd", acb_expClsCd.getValue()); 
    dma_condition.set("isModifyOnly" , "false");

    $c.sbm.execute(sbm_retrieveAgreementVolume);

};



//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.btn_save_onClick = async function (e) {
    let tempSeq = -1;
    if (! await $c.gus.cfValidate([gr_agreementVolumeResults])) return;

  	for(i = 0; i < ds_inputVolumeResults.getTotalRow() ; i++)  	{
  	 	tempSeq = ds_inputVolumeResults.getCellData(i,"seq"); 

  	  	if( (tempSeq == 0) )
	  	  ds_inputVolumeResults.modifyRowStatus(i, "C");  
	} 	 

	if (await $c.win.confirm(MSG_CM_CRM_001)) {
        $c.sbm.execute(sbm_save);
    }  	 
};


//-------------------------------------------------------------------------
// 본선 관리 번호 조회 팝업 클릭
//-------------------------------------------------------------------------
scwin.btn_cvsslMgntNo_onClick = async function (e) {
    //팝업 화면에 데이터 보내는 방법 1. json형태로 팝업화면에서 getParameter로 받기
    let params = new Array();

    params[0] = ed_cvsslMgntNo.getValue();

    // 팝업 옵션 설정
    let opts = {
        id: "taxPop", 
        modal: true,
        popupName: "본선관리번호검색팝업",
        width:  1100,                   
        height: 650
    };

    let url = "/ui/ds/op/wrkplan/stvwrkplan/op_204_01_07p.xml"
    //상세화면 호출
    let rtnValues = await $c.win.openPopup(url, opts, params)
    // let rtn = await $c.win.openPopup("/ui/ds/op/wrkplan/stvwrkplan/op_204_01_07p.xml", options, args);       

    if(rtnValues != null) {
        $c.gus.cfSetReturnValue(rtnValues, ed_cvsslMgntNo);
        ed_cvsslMgntNo.setValue(rtnValues[0]);
    }

};


//-------------------------------------------------------------------------
// 본선 관리 번호 조회 팝업 포커스 아웃
//-------------------------------------------------------------------------
scwin.cvsslMgntNo_blur = async function (e) {

    if(ed_cvsslMgntNo.getValue() == "" || ed_cvsslMgntNo.getValue() == scwin.oldData) {
        return;
    }

    let args = new Array();

    args[0] = ed_cvsslMgntNo.getValue();

    // 팝업 옵션 설정
    let options = {
        id: "taxPop", 
        modal : true,
        popupName: "본선관리번호검색팝업",
        width:  1100,                   
        height: 650
    };

    //상세화면 호출
    let rtn = await $c.win.openPopup("/ui/ds/op/wrkplan/stvwrkplan/op_204_01_07p.xml", options, args);       

    if(rtn == null || rtn == "" || rtn == undefined) {
        ed_cvsslMgntNo.setValue("");
    } else {
        $c.gus.cfSetReturnValue(rtn, ed_cvsslMgntNo);
        ed_cvsslMgntNo.setValue(rtn[0]);
        scwin.oldData = rtn[0];
    }

};


//-------------------------------------------------------------------------
// 데이터 로드 완료시
//-------------------------------------------------------------------------
scwin.ds_inputVolumeResults_ondataload = function () {
    if(ds_inputVolumeResults.getTotalRow() == 0) {
        $c.win.alert(MSG_CM_ERR_003) // 해당되는 자료가 존재하지 않습니다
    }

    $c.gus.cfEnableBtnOnly([udc_gr_Row, btn_save]);

    spa_totalRow.setValue(ds_inputVolumeResults.getTotalRow());

    gr_agreementVolumeResults.setFocusedCell(0, 0);
    gr_agreementVolumeResults.setFocusedCell(1, 1);
};

//-------------------------------------------------------------------------
// 협정 물량 데이터 로드 완료시
//-------------------------------------------------------------------------
scwin.ds_agreementVolumeResults_ondataload = function () {
    if(ds_agreementVolumeResults.getTotalRow() == 0) {
        $c.win.alert($c.data.getMessage(MSG_CM_ERR_003, "협정물량"));
    } else {
        for(i = 0; i < ds_agreementVolumeResults.getTotalRow(); i++){

            ds_inputVolumeResults.setRowData((ds_inputVolumeResults.getTotalRow()), ds_agreementVolumeResults.getRowData(i), false);
        }
    }

    // ds_agreementVolumeResults.setJSON([]);

    spa_totalRow.setValue(ds_agreementVolumeResults.getTotalRow());

};


//-------------------------------------------------------------------------
// 협정 물량 데이터 로드 완료시
//-------------------------------------------------------------------------
scwin.sbm_Save_submitDone = function (e) {

    $c.win.alert(MSG_CM_INF_001) // 성공적으로 저장하였습니다.
    scwin.btn_retrieve(); 

};



//-------------------------------------------------------------------------
// 그리드 팝업 콜백
//-------------------------------------------------------------------------
udc_grid_commonPopUp_Callback = function(ret) {

    let rowIndex = gr_agreementVolumeResults.getFocusedRowIndex();
    $c.gus.cfSetGridReturnValue(ret, ds_inputVolumeResults, rowIndex, "commCd", "commNm");	


}


//-------------------------------------------------------------------------
// 행추가
//-------------------------------------------------------------------------
scwin.f_AddRow = function() {

	let selectRow = ds_inputVolumeResults.getRowPosition();  

    let insertRow = ds_inputVolumeResults.insertRow(); 
    let cvsslMgntNo ="";
    let impExpClsCd ="";

    if(selectRow < 0)  {
    	cvsslMgntNo = ed_cvsslMgntNo.getValue();
   		impExpClsCd = acb_expClsCd.getValue();
    }else{ 
        cvsslMgntNo = ds_inputVolumeResults.getCellData(selectRow,"cvsslMgntNo");
        impExpClsCd = ds_inputVolumeResults.getCellData(selectRow,"impExpClsCd");
	 }
	// 행  copy
	ds_inputVolumeResults.setCellData(insertRow,"cvsslMgntNo", cvsslMgntNo);
	ds_inputVolumeResults.setCellData(insertRow,"impExpClsCd", impExpClsCd);	 
	ds_inputVolumeResults.setCellData(insertRow,"seq", 0);

    ds_inputVolumeResults.setCellData(insertRow,"cntrBulkClsCd", ds_inputVolumeResults.getCellData(selectRow,"cntrBulkClsCd"));
	ds_inputVolumeResults.setCellData(insertRow,"odrNo", ds_inputVolumeResults.getCellData(selectRow,"odrNo"));
	ds_inputVolumeResults.setCellData(insertRow,"agrVolmgntNo", ds_inputVolumeResults.getCellData(selectRow,"agrVolmgntNo")); 

	ds_inputVolumeResults.setCellData(insertRow,"sellItemCd", ds_inputVolumeResults.getCellData(selectRow,"sellItemCd"));	 
	ds_inputVolumeResults.setCellData(insertRow,"commCd", ds_inputVolumeResults.getCellData(selectRow,"commCd"));
	ds_inputVolumeResults.setCellData(insertRow,"commNm", ds_inputVolumeResults.getCellData(selectRow,"commNm"));

    gr_agreementVolumeResults.setFocusedCell(insertRow, 1);
    spa_totalRow.setValue(ds_inputVolumeResults.getTotalRow());
}

//-------------------------------------------------------------------------
// 행삭제
//-------------------------------------------------------------------------
scwin.f_DeleteRow = function() {
    let rowIndex = gr_agreementVolumeResults.getFocusedRowIndex();

    if(ds_inputVolumeResults.getRowStatus(rowIndex) == "C") {
        ds_inputVolumeResults.removeRow(rowIndex);
    } else {
        ds_inputVolumeResults.deleteRow(rowIndex);
        gr_agreementVolumeResults.setFocusedCell(rowIndex, 0);
    }

}

scwin.sbm_retrieve_submitDone = function (e) {
    gr_agreementVolumeResults.setFocusedCell(0, 0);


};



//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.btn_fieldClear_onclick = function (e) {
    $c.gus.cfInitObjects(tbl_condition, null);
    ed_cvsslMgntNo.focus();
};


//-------------------------------------------------------------------------
// 그리드 편집모드 진입시 
//-------------------------------------------------------------------------
scwin.gr_agreementVolumeResults_onbeforeedit = function (rowIndex, columnIndex, value) {
    scwin.oldData = value;
};



//-------------------------------------------------------------------------
// 그리드 편집 후 
//-------------------------------------------------------------------------
scwin.gr_agreementVolumeResults_onafteredit = function (rowIndex, columnIndex, value) {
    let colid = gr_agreementVolumeResults.getColumnID(columnIndex);



    if(colid == "commNm") {
        if(value == "") {
            ds_inputVolumeResults.setCellData(rowIndex, "commCd", "");
            return;
        }

        if(scwin.oldData == value) {
            return;
        }
        scwin.f_openCommonPopUp(1, "commNm", ds_inputVolumeResults.getCellData(rowIndex, "commNm"), 'F', 'T', "onafteredit");
    } else if (colid == "agrQty" && value == "") {
        ds_inputVolumeResults.setCellData(rowIndex, colid, 0);
        ds_inputVolumeResults.setCellData(rowIndex, "rmdrQty", 0);

    } else if (colid == "agrWt" && value == "") {
        ds_inputVolumeResults.setCellData(rowIndex, colid, 0.000);
        ds_inputVolumeResults.setCellData(rowIndex, "rmdrWt", 0.000);

    } else if (colid == "agrCbm" && value == "") {
        ds_inputVolumeResults.setCellData(rowIndex, colid, 0.000);
        ds_inputVolumeResults.setCellData(rowIndex, "rmdrCbm", 0.000);

    } else if (colid == "agrQty" && value != "") {
        ds_inputVolumeResults.setCellData(rowIndex, "rmdrQty", value);

    } else if (colid == "agrWt" && value != "") {
        ds_inputVolumeResults.setCellData(rowIndex, "rmdrWt", value);

    } else if (colid == "agrCbm" && value != "") {
        ds_inputVolumeResults.setCellData(rowIndex, "rmdrCbm", value);

    }



};


scwin.gr_agreementVolumeResults_ontextimageclick = function (rowIndex, columnIndex) {
    scwin.f_openCommonPopUp(1, "commNm", ds_inputVolumeResults.getCellData(rowIndex, "commNm"), 'F', 'T', "onafteredit");
};


//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {

    let columnId = gr_agreementVolumeResults.getFocusedColumnID();
    let rowIndex = gr_agreementVolumeResults.getFocusedRowIndex();

    let evNm = arguments[5] || "";

    if (evNm && $c.win.getEventList(gr_agreementVolumeResults, evNm)) {
        scwin.eventCnt++;
    }

    $p.setTimeout(function () {
        scwin.eventCnt = 0;
    }, { delay: 1500 });


    if(columnId == "commNm"){ // 여긴 품목/품명 팝업 처리
        if(scwin.eventCnt == 1) {
            ds_inputVolumeResults.setCellData(rowIndex,"commNm", "");
            ds_inputVolumeResults.setCellData(rowIndex,"commCd", "");
            let gubun = ",,,T3";
            udc_grid_PopUp.setSelectId("retrieveCommInfo");
            udc_grid_PopUp.cfCommonPopUp(
                udc_grid_commonPopUp_Callback
                ,""					// 화면에서의 ??? Code Element의	Value
                ,pName					// 화면에서의 ??? Name Element의	Value
                ,"T"				// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                ,'3'					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                ,"품목/품명코드,품목/품명,구분"					// Title순서	
                ,'105,190,70'					// 보여주는 각 컬럼들의 폭	
                ,'4,5,6,7,8,9,10'					// 컬럼중에서 숨기는	컬럼 지정	
                ,gubun	//컨테이너 벌크구분을 넘김
                ,'440'					// POP-UP뛰을때 원도우의	사용자 정의	폭
                ,'500'					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                ,null					// 윈도우 위치 Y좌표	
                ,null					// 윈도우 위치 X좌표
                ,null					// 중복체크여부	("F")
                ,"F"					// 전체검색허용여부	("F")
                ,"품목/품명,품명코드,품명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            )
        }
    }
}


//-------------------------------------------------------------------------
// 그리드 셀 클릭 
//-------------------------------------------------------------------------
scwin.gr_agreementVolumeResults_oncellclick = function (rowIndex, columnIndex, columnId) {
    if(columnId == "agrQty"  || columnId == "agrWt" || columnId == "agrCbm" ) {
        if (ds_inputVolumeResults.getCellData(rowIndex , "isRowEdit" ) == "F" ) { 
            gr_agreementVolumeResults.setCellReadOnly(rowIndex, "agrQty", true);
            gr_agreementVolumeResults.setCellReadOnly(rowIndex, "agrWt", true);
            gr_agreementVolumeResults.setCellReadOnly(rowIndex, "agrCbm", true);
        }else { 
            gr_agreementVolumeResults.setCellReadOnly(rowIndex, "agrQty", false);
            gr_agreementVolumeResults.setCellReadOnly(rowIndex, "agrWt", false);
            gr_agreementVolumeResults.setCellReadOnly(rowIndex, "agrCbm", false);
        }
    }
};
